import React, { useState } from 'react';

function BuyerDash() {
  const [cart, setCart] = useState([]);
  const products = [
    { id: 1, name: 'Organic Tomatoes', price: 2.5, stock: 'In Stock' },
    { id: 2, name: 'Fresh Potatoes', price: 1.8, stock: 'Low Stock' },
  ];

  const addToCart = (p) => setCart([...cart, p]);

  return (
    <div style={{ padding: '20px' }}>
      <h2>Available Products</h2>
      <div style={{ backgroundColor: '#e8f5e9', padding: '15px', borderRadius: '8px', marginBottom: '20px' }}>
        <strong>✨ AI Assistant:</strong> "Tomato prices are expected to drop in 2 weeks. Buy only what you need now!"
      </div>

      <div style={{ display: 'flex', gap: '15px' }}>
        {products.map(p => (
          <div key={p.id} style={{ border: '1px solid #ccc', padding: '15px', borderRadius: '10px' }}>
            <h3>{p.name}</h3>
            <p>Price: ${p.price}/kg</p>
            <button onClick={() => addToCart(p)}>Add to Cart</button>
          </div>
        ))}
      </div>

      <div style={{ marginTop: '30px' }}>
        <h3>Your Cart ({cart.length} items)</h3>
        <p>Total: ${cart.reduce((sum, item) => sum + item.price, 0).toFixed(2)}</p>
      </div>
    </div>
  );
}

export default BuyerDash;
